-- Reports 3501-3671 of 3671

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('d3b170ad-1f46-5725-b193-c8219ccecc47','ff349eff-60d1-5916-a2b5-9589d85c3eef','2026-04-03 14:37:10','MIC','Central diestro de estatura 1.85 o más. Buen físico, rápido y fuerte, con capacidad para defender hacia atrás. Destaca en cobertura de profundidad, sólido en duelos. En juego asociativo va hacia adelante, sobre todo con pases largos (destaca especialmente aquí).','NB','Seguir'),
  ('c73a0f93-cc32-5db8-89b0-dbb9c7b1347d','db0833b6-25a1-5dd2-9a47-b53770947e56','2026-04-03 16:11:08','vs Quart','Central diestro de buen perfil físico, aunque con dudas sobre su velocidad. Destaca por su capacidad para ganar metros en conducción y filtrar pases por zonas interiores. Tenerlo en cuenta, sin terminar de convencerme al 100%.

Actualizo  vs Barcelona: es lento, le cuesta el retroceso y debe ser más agresivo.','NB',NULL),
  ('745bbb5f-180b-55ff-bf26-107f6ad841d6','bfac7d46-6477-5ca6-946a-fb293faeb37b','2026-04-03 16:13:18','vs Granollers','Extremo zurdo por derecha. Estatura media, rápido y explosivo. Perfil de extremo encarador, hábil, con uno contra uno.','NB','Seguir'),
  ('aaede3d4-6e1a-5939-a178-398396cff5f7','ee67da3a-ab30-5042-81ef-1988913886e6','2026-04-03 19:12:40','MIC','Centrocampista al que veo con capacidad de evolucionar como 8, ahora más 10. Es jugador de nivel técnico alto, capacidad de juego entre líneas, habilidad para desequilibrar individualmente. Llegada a área y finalización. En fase defensiva está ganando trabajo aunque aún puede ser más sólido.','NB','Firmar'),
  ('d3cb04cb-3a17-5616-90bf-8f6cce7848a6','b8a0da97-0535-5a0f-b2dd-d4e54a8da487','2026-04-03 19:16:28','MIC','Extremo diestro. Perfil físico top, similar a Jesús y Morante por estructura. Rápido y explosivo, con zancada. Aún irregular en su juego pero con cualidades muy positivas.','NB','Firmar'),
  ('f2fb7079-3b76-553a-abdf-522c6f6eb07b','5636029c-8e0e-5a0c-8814-5291f791f1fc','2026-04-03 19:17:35','MIC','Opinión similar a partidos anteriores. Lo veo preparado para siguiente nivel, jugador que destaca por físico, entendimiento del juego y personalidad. Con buena técnica también.','NB','Firmar'),
  ('1e9f3b28-cc19-5aa9-a432-a9fdf11d103b','4b752edf-e483-5adb-9940-1e8b4cdc6557','2026-04-04 09:44:17','MIC','Extremo de buenas cualidades físicas: estatura media, piernas largas, delgado pero fuerte, rápido y explosivo. Se nota que es irregular a nivel técnico. Buen perfil, aún de poco impacto en juego.','NB','Seguir'),
  ('0635427b-22bb-56cf-900c-91200cb682a1','4ea5343a-6b6d-51c2-abce-aee2d59aefce','2026-04-04 12:11:27','MIC','Centrocampista #6 de buena estatura, construido físicamente, fuerte y ágil, dinámico, con recorrido. Calidad en salida de balón, juego asociativo, capacidad de conducción. Agresivo y sólido en duelos individuales, buen trabajo defensivo. Me parece el mejor del Juvenil C.','NB','Firmar'),
  ('ae0f5ed5-42e4-5fae-83bf-1c007831bfd6','1d625e7b-8cbe-57a3-9ee0-545d52b92872','2026-04-04 12:13:16','MIC','Mediocentro #8 de perfil fisico top. +1.85 m, de estructura delgada, con margen de crecimiento en musculatura. No tiene tanto impacto y me genera dudas su trabajo defensivo, pero es un perfil interesante a seguir.','NB','Seguir'),
  ('c88d6d0e-a982-5836-b53d-7ff24799d73a','d2b4a39a-1d1d-50d3-a469-114e88b9552f','2026-04-04 12:15:54','MIC','Extremo zurdo por derecha. Complexión fuerte, rápido y explosivo. Encarador, con desborde y 1v1. Irregular a nivel técnico y en toma de decisiones.','NB','Seguir'),
  ('a2d7a400-1989-57a7-b7cf-6cf3371c1012','f0ee2419-3318-51ab-9293-38cb8a8cf38a','2026-04-04 12:17:31','MIC','Centrocampista 8-10 de nivel técnico excelente, con grandes recursos para generar ventajas individualmente, crear ocasiones, y dar último pase/terminar con remate. Es intenso en fase defensiva, trabajador y activo en transiciones. Me deja dudas su perfil físico, ya que no es alto ni poderoso y eso puede condicionarlo como 8.','NB','Seguir'),
  ('17d13c53-2cd8-57c6-a5a0-b7ba478d486a','5618ae4b-2749-5978-8b9b-fc52f2c26b29','2026-04-04 12:19:35','MIC','Central diestro de 190 aprox, dudas sobre velocidad ya que lo noto algo pesado pero creo que lo compensa bien con lectura. Contundente en duelos individuales, va al choque y gana. Destaca en juego aéreo. OK con balón sin destacar especialmente.','NB','Firmar'),
  ('a35551c5-bd81-56a3-bfb0-5b2eed37b3e5','6f560132-7a65-537e-a142-51e62057d4c1','2026-04-04 12:20:47','MIC','Delantero centro de buen perfil físico: alto, fuerte, ágil. Buen juego fuera del área, capaz de jugar de espaldas y atacar espacios. Buenos movimientos dentro del área. Me parece un delantero interesante pese a que no le veo tanto impacto en área.','NB','Seguir'),
  ('8d1be15a-ff63-533e-bffd-8f5a13595879','f3afaad6-91a0-55b4-84be-04e97e757b39','2026-04-04 14:11:06','MIC vs Betis','Extremo diestro por izquierda. Perfil de extremo Jan Virgili, tren inferior potente, rápido y explosivo. Encara y se va, tiene buena técnica, desequilibra en carrera y en espacios reducidos.  No tiene acciones de finalización. Jugador algo pasivo en fase defensiva. 

Tiene cualidades muy interesantes, intentar conseguir más partidos.','NB','Seguir'),
  ('70a670a8-86f9-5281-8f76-33ca5aed69a6','d26ce74f-6391-53f8-8f45-8f8163ba7ea3','2026-04-04 23:12:50','MIC vs Chelsea','Extremo diestro por izquierda. Perfil físico medio en cuanto a estatura, pero muy rápido y explosivo. Jugador de ritmos altos, vertical, desequilibrante en el uno contra uno.','NB','Seguir'),
  ('150eb88a-d2b1-5394-a569-4f4db12cb697','029b6000-d6e1-5014-b8c7-d1d42c1e2cf8','2026-04-05 11:23:37','MIC','Lateral derecho de buen perfil físico: estatura media-alta, potente, rápido, con recorrido. Clara vocación ofensiva, con llegada a ataque, recursos para desequilibrar individualmente, generar en conducción y pisar área, incluso finalizar. Irregular en fase defensiva pero con agresividad e intensidad correctos, debe ganar mayor solidez en 1v1.','NB','Firmar'),
  ('7c49ebc2-da12-5e2a-a46e-18ed6e583462','1048e894-8494-59c5-ab3b-509b0501cca7','2026-04-05 13:51:57','vs  Betis','Extremo rápido, encarador, que busca el 1v1. En mi opinión le falta mayor poderío físico para marcar diferencias. No lo veo superior en condiciones a Rafa Oya, por ejemplo.','NB',NULL),
  ('51c678c1-1862-536c-901a-0142488f355d','5ac693e1-ede7-5532-846f-531665308edc','2026-04-05 14:50:32','Future Cup','Centrocampista perfil #8 - #10 de gran perfil físico: alto, fuerte, veloz, dinámico. De nivel técnico alto, recursos para generar individualmente y asociarse. Llegador, con gran capacidad de finalización.','NB','Firmar'),
  ('92a5c8a3-2359-56a7-b722-85240ff59138','8bcc6303-af49-5a2a-a3f9-2aaee5875939','2026-04-05 15:12:18','MIC','Central diestro de perfil físico top, estatura cercana al 1.90. Es fuerte, contundente en duelos individuales, sólido por arriba. Tiene buen pie en salida de balón, capaz de generar ventajas.','NB','Firmar'),
  ('a2d999e7-8c74-574c-b55b-9cdfa25d47c1','c905e100-881c-57a8-9cf9-12492e17dec0','2026-04-05 15:14:02','MIC','Lateral derecho perfil Adrián Martínez. Físico top para posición: fuerte, rápido, con ida y vuelta. Tiene calidad y recursos en ataque, genera en conducción, llega bien desde segunda línea. En defensa es serio para afrontar duelos.','NB','Firmar'),
  ('60e679ce-60af-59b1-821c-6fb7e33fe97a','c2a8a5c2-d1b5-51d7-9bf9-24f64d102f79','2026-04-05 16:13:48','MIC','Lateral izquierdo perfil que nos gusta. Buen prototipo físico, puede ser central perfectamente por estatura. Es rápido, con recorrido. Muestra capacidad para avanzar en conducción y generar en ataque. Con buenos conceptos defensivos.','NB','Seguir'),
  ('1816f37b-7543-53cf-adad-dd948ceb253e','c8b306be-16e6-59bc-8bab-ca15e36d8fc9','2026-04-05 16:15:48','MIC','Repito opinión. Es un buen perfil, tiene físico interesante. Creo que no tiene suficientes recursos para ser extremo, me da sensación parecida a Domi Taucas.','NB',NULL),
  ('be91f16a-7fd5-5ec4-8215-57edaed6990f','28fbd152-d201-5ee0-ba5a-b420787b3472','2026-04-05 19:24:55',NULL,'Extremo que también puede jugar por dentro. Lo he visto en directo y en vídeo, en ambas da una buena sensación en cuanto a físico (parece superior 1.80, es rápido y fuerte). Creo que le faltan más recursos para ser diferencial en banda. Jugador que está bien y hay que seguir, pero que no me termina de convencer para firmar.','NB','Seguir'),
  ('5e360da8-4ffa-5a49-9796-139b4a1552e2','b919697c-c4fa-52d0-a985-e282701ca73b','2026-04-06 16:04:02',NULL,'Josep Cerda es un extremo diestro que juega normalmente por izquierda. Estatura baja (cercana al 1.70 m), de tren inferior potente, buen punto de velocidad (34.3 km/h de máxima) y agilidad aunque sin ser excelente en distancias y sprints (por debajo de los de Minsu con diferencia, por ejemplo).

Destaca por su habilidad en el 1v1. Es uno de los mejores regateadores de Segunda División, tiene repertorio para superar rivales. Maneja bien la zurda, se siente cómodo por dentro también. 

Llega con frecuencia a área rival, donde tiene capacidad para finalizar. De hecho es más finalizador que pasador. 
Es un jugador bastante intenso en presión y fase defensiva. Realiza un buen trabajo sin balón.

Perfil de extremo interesante, que por estilo puede tener cabida en Primera en próximos años. No me parece top, pero sí con posibilidades si mantiene este nivel.','NB','Seguir'),
  ('728c8910-8c6e-553c-8bf5-fdef9f9b4644','c1d6f6b6-1b7f-5cdc-9d59-c1ba85a73a87','2026-04-06 17:09:59','Ajax Cup','Central de buenas condiciones pero notablemente por debajo del potencial de Garrido y Lemaitre.','NB',NULL),
  ('ec0d63c7-76ec-5e3e-bd82-ca72dfdad552','77628ae8-448b-560c-942f-ad52b172907c','2026-04-06 17:11:09','Ajax Cup','Como central no lo veo destacando. Incluso algo bajo para esa posición quizás. No lo veo generar con balón, ni tampoco es especialmente rápido ni contundente.','NB',NULL),
  ('85104a1a-b6e3-56df-a38f-f1a471feccd0','79d65acd-d6f0-55ff-b250-18eec8941cba','2026-04-06 17:12:20','Ajax Cup','Perfil de #6 de estatura baja, buen juego asociativo, capacidad de creación. Físicamente no destaca, no lo firmaría aunque el RM lo valora.','NB',NULL),
  ('4e6de99f-3af7-5004-ae77-ab0217497d96','526b7f8c-60b6-5b8a-812f-4d6c776f19b5','2026-04-06 17:16:37','Ajax Cup','Primeros meses tras recuperación. Se nota que le falta explosividad, punto importante de su juego. Físicamente no está bien y no es capaz de sacar ventajas. Detalles de calidad cerca del área pero poco más.','NB',NULL),
  ('d9c2aaa0-3a4f-5d78-88de-f2a120599208','d73a8091-6159-5ce6-8a97-836dcd5a1927','2026-04-06 22:29:46','vs Castellon','Mediocentro de estatura baja, delgado, ágil, rápido, con recorrido. Abarca metros sin balón. Tiene buen nivel técnico, es vertical, juega hacia adelante. Destaca por energía para presionar y afrontar duelos. Jugador que está por encima de la categoría.','NB','Firmar'),
  ('9b974596-ff75-5417-a988-9af01cf8bec6','70e4cdf9-8905-5bb7-bf6b-c5b937efe45b','2026-04-07 11:30:52','General','Siren Diao es un delantero centro de condiciones físicas muy buenas: alto, fuerte, rápido (cerca del 35 km/h en velocidad punta). Con potencia para atacar espacios e ir en profundidad. Con notables defectos técnicos y de comprensión del juego. 

Le ha costado jugar en fútbol profesional hasta ahora, tanto en Italia, Granada y Mirandés. Deja muchas dudas. Valorar si tiene sentido llamar y decidir, parece que ya no está con su agencia de representación.','NB','Decidir'),
  ('542eafa8-5c75-54d8-9fd4-42ded204269d','bc8cb2ea-81b1-5b79-b03d-53e4ba6ef98f','2026-04-08 16:58:02','Torneo Semana Santa','Extremo zurdo, buen uso de derecha. Perfil físico top: es alto, delgado, buena velocidad sin ser explosivo. Jugador que tiene recursos técnicos, capacidad de conducción y repertorio para finalización. Perfil interesante, con transferencia a niveles más altos.','NB','Firmar'),
  ('23c397b3-6e80-5a23-88c2-5c8c370e8d25','b9ab7273-2173-5898-addc-aeb5018fe5a7','2026-04-08 17:01:40','vs Valencia','Extremo diestro por izquierda. Es rápido, vertical, hábil en situaciones de 1v1, tiene regate y desparpajo. Pocas acciones aunque interesantes, seguirlo. Poca activación sin balón.','NB','Seguir'),
  ('735a5b93-fc5f-5e73-be96-0b41c1a7740a','1fbbb9fb-daa3-59c2-9a5c-04a6e3e61ec0','2026-04-08 17:04:20','vs Valencia','Central diestro de buen perfil físico, notables conceptos defensivos y buen nivel técnico para progresar, sobre todo en conducción y con pases largos. Defensa sólido en duelos individuales, choques, 1v1. Proactivo para salir de zona, buen defensor de área.','NB','Firmar'),
  ('dfe20009-3e69-56df-a19b-b3d52af1e16b','ded8b054-4d08-513a-8da6-b0554c0b85fe','2026-04-08 17:08:05','vs Zaragoza','Perfil de #8 de buena estatura, delgado, con margen de crecimiento físico, da sensación de algo lento en corto. Futbolista de buen nivel técnico, capaz de progresar en conducción, superar líneas y acercarse a área rival.','NB','Seguir'),
  ('5e398ea5-c36b-56ef-88e2-069be7895605','a9e6e5e9-9cee-511f-89b4-7e8b66d3d3d8','2026-04-09 09:33:42','partidos de liga','Jugador salvaje. Con condiciones innatas interesantes, pero aún por hacer en todo sentido. Pocos conceptos tácticos y de entendimiento del juego, conceptos defensivos e irregular técnicamente. Es un jugador que me gusta, quiero seguirlo.','NB','Seguir'),
  ('877288de-4b20-5178-a53c-fa100bb5f1d2','75252fa6-fb3c-59ba-8f48-48f802a496ee','2026-04-09 09:37:01','vs Penya Bons Aires','Delantero centro de cualidades físicas top. Técnicamente mejorable e impacto en juego también. Muy alto, fuerte y buena velocidad.','NB','Seguir'),
  ('6288094a-958e-5456-a09e-c35d56bb8910','50511be2-c282-5fac-b06f-ab5903752504','2026-04-09 13:21:30','vs Flecha Negra','Extremo de buen perfil físico pero que genera poco impacto en general. No le veo suficiente capacidad de desequlibrio individual. Se le ve buen perfil físico sin ser excelente. No le veo diferencial, me genera dudas.','NB',NULL),
  ('0cc3f065-0396-569d-beff-b7efe4d984f2','9c87d677-cc5b-5c4c-be3f-3522ec0994e9','2026-04-10 09:49:54','vs Burgos B','Delantero centro de condiciones físicas excelentes, muy fuerte y rápido. Es rápido para atacar el espacio, capacidad de finalización. Delantero top, potencial primer equipo.','NB','Firmar'),
  ('17eb04cb-753e-51ba-96f1-4c9228ab2810','5b182986-9408-5b7e-9bbc-d978ec28372a','2026-04-10 10:07:05',NULL,'#8 de perfil físico normal, buen toque de balón, intenso en presión y fase defensiva. Ver más.','NB','Seguir'),
  ('384d7a38-345d-5f03-b59f-cc00c2b9fe74','5a985f01-211f-5792-8b1c-74043ea826ec','2026-04-10 11:10:51',NULL,'Marcos Luna es lateral derecho de buen perfil físico: supera el 1.80 m, potente y rápido. Con datos físicos superiores a la media, capacidad para repetir esfuerzos a alta intensidad. 

Jugador sólido en fase defensiva, difícil de superar en situaciones de uno contra uno, aplicado y con conceptos claros. Mejorable en juego aéreo. Activo en presión en campo rival y proactivo para afrontar duelos. 

En ataque tiene nivel técnico aceptable, sin destacar. Es algo rígido en su juego, vertical en acciones, puede ganar metros en conducción. Menos recursos en uno contra uno en espacios reducidos. Tiene buena arrancada y suele llegar a último tercio, aunque le falta finura para último pase. En ataque es correcto sin destacar. demasiado. 

En mi opinión es lateral derecho de Segunda alta / Primera baja. Valorar si nos interesa este tipo de perfil.','NB','Decidir'),
  ('69546b8f-fad4-5e51-acc0-2af98c7648e7','0560b3b0-2076-55a2-aac6-b446b41f457b','2026-04-10 11:26:48','vs Burgos B','Mediocentro de perfil físico bien, sin parecer excelente. Pocos minutos, no se pueden sacar conclusiones.','NB',NULL),
  ('3de218fb-4d78-5231-b99b-d7584d4228a9','c33a9afa-350b-5a61-8f56-d3f95b13d4b1','2026-04-11 14:58:28',NULL,'Martin es un central de buen rendimiento, con potencial claro de fútbol profesional. Aún así me genera ciertas dudas sobre su potencial, bastante inferior al de Huseini. Le falta mayor agresividad y capacidad para defender a campo abierto. También más recursos con balón.','NB',NULL),
  ('3e3b64c7-a1b2-5ae8-a5b6-b83226a5b884','7e30c9ff-719b-562c-bc31-15e3bec5924d','2026-04-11 21:12:45',NULL,'Mediocentro #8 de buen perfil físico. Jugador de 1.85 m aprox (o más), fuerte, más ágil de lo que parece a simple vista. Vertical en acciones, llegador, con buen golpeo. Me deja dudas su trabajo sin balón, donde tiene margen de crecimiento. Me recuerda a Homenchenko','NB','Seguir'),
  ('dca4bd07-2dcb-586a-b9cd-6c57f55908c9','b8b8aa80-d41b-58e1-939d-33d8eeeed79d','2026-04-11 21:15:33',NULL,'Juega de mediapunta, su mejor posición. Gran nivel técnico, capacidad de desequilibrio, habilidad en espacios reducidos, con llegada a área. Es especialmente intenso en presión hacia adelante.','NB','Firmar'),
  ('7118bda0-969a-5951-b077-4e52e4f07407','83d173c8-72d4-5ad5-8289-11851d5260a1','2026-04-11 21:27:13',NULL,'No tengo claro que sea como extremo, pero es un futbolista con físico privilegiado por lo que le veo transferencia a fútbol profesional.','NB','Seguir'),
  ('7cbd5496-8317-50b7-86de-ae6387bfd84f','575464c4-68d0-5615-99b6-f8adafb14c4a','2026-04-11 23:40:33','vs Atletico','Centrocampista #8 de perfil físico normal, parece adaptarse a Primera en este sentido. Le falta algo más de ritmo quizás. Jugador de buen nivel técnico, que juega hacia adelante y se acerca a área rival. Intenso y agresivo en fase defensiva. No me parece top, sí jugador válido para este contexto de Sevilla. Y con minutos en Primera va a crecer.','NB','Decidir'),
  ('2a71875c-5f63-5f95-9cfa-537bc80c38f6','551a445d-f976-56ec-8691-c06c64e6791b','2026-04-11 23:43:41','vs Sevilla','Lateral izquierdo de físico medio-bajo en estatura, rápido y explosivo, tiene recorrido. Es intenso en sus acciones, con ida y vuelta. Buen nivel técnico, con recursos para generar. Centra bien, tiene criterio. Agresivo en fase defensiva, con margen de mejora. 

Es lateral de Primera.','NB','Firmar'),
  ('8cd02346-ad74-568c-a8a9-e5a0ffafaefa','dc38c4a7-384a-50c4-ae81-6fb90d124ca3','2026-04-11 23:46:08','vs Sevilla','Misma opinión. Central lejos de nivel ATM, no lo veo especial en ningún sentido. Puede tener recorrido profesional pero me cuesta verlo asentarse en Primera.','NB',NULL),
  ('68383389-5577-5534-a373-12560eafbe06','09197bbb-c2a1-56f0-852c-4bd8056e21f6','2026-04-11 23:48:41','vs Sevilla','Lateral derecho de buen perfil físico, con recorrido e ida y vuelta. Jugador de buen nivel, aunque no lo veo tan diferencial en fase ofensiva ni sólido en defensa como para considerarlo preparado para primer equipo. Peor que Budesca.','NB',NULL),
  ('24a2296c-af9d-5d92-8bd1-6b20be59e604','63b137d5-786b-5537-8d3f-3d5bce25dce5','2026-04-11 23:50:44','vs Sevilla','Jugador que por características va a ser pasado a banda en fútbol profesional. No es su posición, no tiene tantos recursos para destacar ahí. Ni físicos ni de desequilibrio en 1v1.','NB',NULL),
  ('6ac03ceb-455a-5325-95f7-8cdee92d1508','151eab0b-00eb-5f62-aa4b-fa9b6288da93','2026-04-12 13:59:22','vs Inter SJ','Central diestro de buenas condiciones físicas, estatura cercana al 1.90 sin llegar. Buena predisposición para jugar hacia adelante con balón, también en conducción. Me deja dudas a nivel defensivo, lo veo algo blando y con problemas en cobertura de profundidad','NB',NULL),
  ('5c6c2044-a86e-5628-8821-3510531b8f30','50a6a85f-3e6b-52d5-ba89-f77b20c6dbb1','2026-04-12 14:02:27','vs Inter SJ','Más allá de estatura, nada destacable. Poco ritmo, lento, frágil.','NB','Descartar'),
  ('9b17e596-f067-5e9b-8d39-dad8c619b511','8df15040-d7de-5bde-83e5-1bb6de85e5ba','2026-04-12 14:04:08','vs Inter SJ','Poca velocidad y desborde para ser extremo. No es perfil.','NB',NULL),
  ('579abc32-7bfd-5c0b-9b6a-db676c761623','f007ea82-e67b-5672-b631-b9de2c400bfc','2026-04-13 06:39:07','vs Castellonense','Ya más asentado como carrilero en Villarreal C. Es jugador de buenas condiciones físicas, que puede crecer en la posición. Sin ese punto de finura para ser extremo, pero con espacio por delante tiene más potencial. 

Priorizar Moussa, son muy amigos.','NB','Seguir'),
  ('bbf6e3d5-6d37-599c-8634-05536254262c','83ebd693-dff5-55ee-8331-5753ec2fe001','2026-04-13 06:40:46','vs Castellonense','También asentado como carrilero en filial ya. Jugador de buenas condiciones físicas, que tiene potencial en la posición por capacidad de repetir esfuerzos, trabajo defensivo y llegada en carrera desde atrás.','NB','Seguir'),
  ('6feed636-5cfb-5342-a2c0-d8dca60aadb8','1a633f3b-0484-5887-82c4-a60cc6f7af51','2026-04-13 06:42:24','vs Castellonense','Jugador con potencial enorme para evolucionar como un #8 de ida y vuelta. Perfil Premier League total.','NB','Firmar'),
  ('ba959c36-eb12-59ea-add0-347cff310a68','ecf817f1-9ce3-5ef0-8a29-4ef503421b56','2026-04-13 06:50:18','Castellonense','Juega de delantero, ahí la única duda es su estatura. Es un jugador rápido y explosivo, con 1v1, que ataca espacios y tiene desequilibrio individual.','NB','Firmar'),
  ('ac7c3cda-4417-5e56-af77-b016706bfd6f','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2026-04-13 06:52:00','vs Sant Andreu','Extremo de cualidades físicas espectaculares. Jugador muy fuerte, rápido, con recorrido. Es capaz de producir por físico, más allá de que no sea fino con balón. Yo le veo llegada a Primera.','NB','Firmar'),
  ('fa4dfd44-d5ef-5a1f-b168-5375e8c78275','1c4dc95b-e711-5eb3-ac85-2e2b02025890','2026-04-13 06:56:06','vs Sant Andreu','Lateral derecho de buen perfil físico: alto, fuerte, rápido, con recorrido. Es perfil interesante, sin destacar por su nivel técnico ni impacto en ataque.','NB',NULL),
  ('85bbdfb8-b841-5704-b8d9-c33adfd6f652','2f11ef02-aef0-5f04-bd94-4c56642f093b','2026-04-13 06:58:06','vs Sant Andreu','Opinión similar. Creyendo que va a tener fútbol profesional la próxima temporada, no lo noto con la sobriedad que debería a estas alturas en Segunda RFEF.','NB',NULL),
  ('8725d709-ce73-57b1-977a-ee01686cdc60','b35d4619-ef72-58f9-a637-21bd5b5144ab','2026-04-13 06:59:49','vs Sant Andreu','En pocos minutos juega bien fuera del área, gira, busca acciones de desequilibrio individual y finaliza. Es un delantero centro con nivel técnico alto, gran capacidad de remate. Debe fortalecer físico pero potencial de fútbol profesional próxima temporada.','NB','Firmar'),
  ('71919de6-62b0-5fef-8b02-f588a1526530','97f0e3c2-2ace-5b36-83dd-faeacbdf8792','2026-04-13 13:13:14','sdf','dfg','RP',NULL),
  ('3812b15e-5d3c-5231-8b5c-2bac484dbabc','97f0e3c2-2ace-5b36-83dd-faeacbdf8792','2026-04-13 13:13:14','CASTELLÓN JUV. A - Hércules Juv. A','Extremo diestro de estatura media y complexión delgada. En este partido le he visto muy rápido en carrera y con unos primeros cinco metros muy potentes. De momento no me parece un jugador más interesante que eso, pero merece la pena seguirle, especialmente en el salto al fútbol semiprofesional.','RP','Seguir'),
  ('e8d9b5fb-d474-5c3c-95d8-525ecb9781eb','a368b43b-4598-5d6b-987a-e4b3bf15c986','2026-04-13 13:17:10','CASTELLÓN JUV. A - Hércules Juv. A','Central diestro en línea de tres. Estatura algo superior a 1''75 m, complexión fuerte. Buenas condiciones, pero partido discreto.','RP',NULL),
  ('49f4dd4b-a216-53ac-a219-c0f71d1d7682','05d9e8ed-5404-563b-ab5e-f6b2891ae708','2026-04-13 13:18:36','Roda Juv. B - VALENCIA JUV. B','Atacante zurdo, en el partido actuando como delantero centro, con una estatura alrededor de 1''85 m y complexión fuerte. Rápido y potente en carrera. Participativo, pero técnicamente es muy justo.','RP',NULL),
  ('409ac532-c8bc-51dc-a948-e061ae1e2cce','3b5dc9c5-9c92-5083-80f8-0289e6a01243','2026-04-13 13:19:49','Roda Juv. B - VALENCIA JUV. B','Central diestro con una estatura algo inferior a 1''90 m y complexión delgada. No parece especialmente rápido, pero no creo que sea un central lento. Partido sin apenas errores con y sin balón, pero sin tampoco acciones notables.','RP','Seguir'),
  ('bb9003dd-caa9-55c3-9e96-815dacab666b','4ffb9187-c303-5ba5-bce6-87c54fc3c23c','2026-04-13 13:25:04','Roda Juv. B - VALENCIA JUV. B','Defensor zurdo, normalmente lateral aunque hoy jugando como central, con una estatura alrededor de 1''85 m y complexión delgada. No me ha parecido lento. Partido muy correcto con y sin balón. Buen jugador, aunque no sé si top.','RP','Seguir'),
  ('68afa994-977d-517e-9281-9b845819f927','41315d47-f92f-571a-9b97-8d07f8ad0b65','2026-04-15 10:55:39','vs Lanzarote','Extremo - delantero de buenas condiciones físicas sin ser excelentes: no extremadamente rápido ni explosivo, altura media, fuerte. No tiene impacto en el partido, poca participación. Ver más pero no deja buena sensación.','NB',NULL),
  ('b9b2126d-2242-53fa-bf78-a1ceae6857e5','c435f992-f0da-5bc0-b6ea-51f23beea786','2026-04-15 12:00:00','vs Mallorca','Pablo Osan es un extremo de buen perfil físico: +1.80 m, rápido, potente, no explosivo. Me recuerda a Adrián Guerrero (Deportivo) en tipología física y características.

Jugador de buen nivel técnico, destaca por conducciones potentes, maneja ambos perfiles aunque debería confirmar más en su izquierda, juega hacia adelante y pisa área con frecuencia. Tiene buen golpeo. 

En fase defensiva es jugador intenso y aguerrido, trabajador para el retroceso defensivo, activo en presión. Por eso también puede adaptarse a posiciones más atrasadas.','NB','Firmar'),
  ('f946c884-4c8f-59da-8ed4-fa18f4913629','3ca3c6a8-860a-54cf-9ce6-6e0b61aa263b','2026-04-15 12:28:48','vs UCAM','#6 de estatura media-baja, poco impacto en el partido. No destaca','NB',NULL),
  ('c590a894-0b06-5740-8ef5-c762fa8891ab','39295c23-3568-5901-ade5-b060d3b60738','2026-04-15 12:32:29','vs UCAM','Mal físico para posición','NB',NULL),
  ('61dd5cb4-685c-5fdb-ba62-3a5c35f569ce','ccd9e9e3-c767-584b-8e38-bfc7794dafe2','2026-04-15 17:14:16','vs Intercity','Jugador de banda, extremo/lateral. Hace gol pero poco impacto. En DH está destacando, suena para el Real Madrid. Ver más.','NB','Seguir'),
  ('ed958574-d77d-5b72-b91b-77a57a0a1d4d','5a924352-d9f3-57d2-8966-88d5e074c518','2026-04-15 17:19:31','vs Intercity','Delantero centro de buen perfil físico. Buena estatura, fuerte. Con movimientos fuera del área, gol en área. Ver más.','NB',NULL),
  ('17eb6c76-73e2-554c-ac3f-5c02b925a6e8','f6b128ff-85aa-5f3f-8ea5-75fb4253323f','2026-04-15 17:24:15','vs Intercity','Mediocentro  de estatura media, físico no destacable. Zurdo, dinámico, de buen toque y llegada. No me pareció nada especial.','NB',NULL),
  ('df5d4d7b-7b8b-5a7a-894e-1bcbd3a8905c','91aa48a9-2787-59ef-90bb-061618a0ce10','2026-04-15 17:53:09',NULL,'Delantero centro de estatura media-baja, rápido, explosivo, fuerte de tren inferior. No tiene físico de #9 moderno, perfil Iván Romero. Es jugador con recursos interesantes: dinámico en acciones, finaliza bien, tiene recursos en regate. Le falta mayor poderío y juego de espaldas. Ataca bien espacios. 

No lo veo como un #9 de primer nivel, sí como un delantero con posibilidades de llegar a Segunda.','NB',NULL),
  ('4eb0dd2b-9f98-5528-91c9-bfb7b042c970','272fa1ac-dc68-56ae-b054-ab6353d26ce0','2026-04-16 11:58:34','vs Barcelona','Lateral derecho de buen perfil físico: fuerte, rápido, con empuje. Llega bien a ataque, es vertical en acciones. Hace buen trabajo defendiendo a Ruslan Mba.','NB','Seguir'),
  ('d477de7d-5f3e-5312-9db3-c82ef048b987','39c2932d-5faa-5a96-b2e8-e0694a92eee8','2026-04-16 12:04:41','vs Barcelona','Central diestro de gran perfil físico: estatura alta, delgado, con margen de crecimiento en musculatura, velocidad normal sin destacar. Sólido en duelos defensivos, seguro en área. Impone en fase defensiva. Con balón juega hacia adelante, supera líneas con pases interiores. Perfil de central interesante.','NB','Firmar'),
  ('0d8be39d-1f20-5043-96af-f46c32d2e7b4','df47cd80-2d2f-502b-b92a-d2ef189258d0','2026-04-16 12:08:44','vs Espanyol','#6 parecido a Arapio en perfil físico y cacterísticas. Es jugador con transferencia a fútbol profesional por planta, aunque no me parece top por falta de velocidad.','NB','Seguir'),
  ('812c2383-b40b-5a3b-b2b4-e1361ffdc267','617c864c-1cf7-51d1-9a91-48500e84bc2d','2026-04-16 12:10:52','vs Espanyol','Mediocentro de buen perfil físico, dinámico, de gran nivel técnico. Con calidad para manejar juego asociativo, avanzar en conducción, llegar a último tercio. Es perfil top.','NB','Firmar'),
  ('d834a395-cd1e-5d3e-8a70-84448ba2a9f7','91958900-c392-53e9-a972-7e233141cdd0','2026-04-16 12:15:54','vs Espanyol','Perfil de delantero típico Barça, más segundo punta. Estatura baja, rápido, dinámico, de mucha calidad y visión. Dudas sobre adaptabilidad por perfil físico pero tiene condiciones muy buenas.','NB','Seguir'),
  ('406c3571-39bc-50e9-b97a-89408c66dbd1','75f1a310-cb51-5fdd-807b-8d6caeeb2888','2026-04-16 12:18:05','vs Espanyol','Extremo de perfil físico hecho: estatura baja, tren inferior potente, rápido y explosivo. No tiene tanto impacto, lo veo irregular y no tan desequilibrante. Es cierto que tiene buenas acciones en 1v1 y buen golpeo.','NB','Seguir'),
  ('e49ded88-4244-59b8-951b-9861e9e953dd','69d66096-279d-562b-bc3a-929238fdb6aa','2026-04-16 12:27:54','vs Cádiz','Juega de 8, me gusta menos en esa posición. Tiene algunas acciones positivas pero no marca tantas diferentes.','NB','Seguir'),
  ('684d86d1-7dd0-51f4-9570-051184bc2877','7a52fe55-cc43-59e3-b3cb-4363c6892570','2026-04-16 14:14:14','vs Sant Cugat Juv DH','Lateral derecho de perfil físico similar a Masque, también en juego. Es intenso y agresivo en defensa, pese a no ser alto. En ataque destaca mucho, capacidad de conducción, de generar peligro individualmente, asociarse...buen golpeo y centro.','NB','Firmar'),
  ('5f2258ad-3b14-5573-ad53-920d52d31a28','f19c5e79-14d8-5b90-855b-80e304f4bd01','2026-04-16 14:19:53','vs Sant Cugat','Extremo diestro de físico normal, fuerte y estatura media. Tiene buen golpeo para pases, centros...nivel técnico alto. Me falta verle más, pero es hábil y vertical para el 1v1.','NB','Seguir'),
  ('b169198b-e5ab-5228-831a-232031d04c26','a6ad8582-ecfc-5d0a-9411-4c473cf5e5ba','2026-04-16 14:23:21','vs Sant Cugat','Extremo de estatura baja, diestro, rápido, maneja las dos piernas. Perfil diferente a Doblas/Glez pero acaba de llegar y quiero seguirlo de cerca por la captación de Damm.','NB','Seguir'),
  ('ff9c0e0d-c3fc-566c-8986-8c1fbbd5ae06','be20e568-0aaa-598e-97e7-4e81a69b17de','2026-04-16 16:36:06',NULL,'Omar Janneh es un atacante diestro que juega en el Lausanne Sport, de la primera división suiza. Puede actuar como extremo o delantero centro, y tiene una estatura algo inferior a 1’90 m y una complexión delgada, pero muy atlética. 

Se trata de un jugador potente y agresivo con y sin balón. Cuando juega en banda es un extremo que puede hacer mucho daño a campo abierto, ya que tiene una zancada muy poderosa y siempre busca verticalizar y amenazar a la última línea. Parece más peligroso recibiendo al pie que al espacio, ya que tiene calidad para asociarse, un buen cambio de ritmo y habilidad para el desborde. En este sentido tiene buenos recursos para superar a su par, como bicicletas o fintas con el cuerpo antes de acelerar. Otra de sus cualidades es generarse acción de disparo, ya que es capaz de abrir espacios y armar la pierna rápido. Tiene también un buen manejo de ambas piernas, especialmente a la hora de disparar. Como delantero centro tiene facilidad para encontrar portería y una definición bastante buena, aunque aún puede mejorar en cuanto a movimientos en el área. 

En cuanto a otros puntos de mejora, es un jugador que no es del todo fino en algunas ocasiones, y también pierde balones por mala toma de decisión. 

Esta temporada lleva 8 goles y 2 asistencias en 16 partidos con el Lausanne Sport entre liga suiza y Conference League.','RP','Firmar'),
  ('6cbd57f9-199c-56a3-ade4-7cf5e99ff9b7','7b17c417-f53c-55c1-9f36-97fcbfc868d6','2026-04-16 17:37:16','vs Sevilla','Mediocentro #6 de buen perfil físico, margen de crecimiento en musculatura pero buena complexión. Jugador capaz de dirigir salida, gana metros en conducción, fuerte en duelos, con recorrido.','NB','Seguir'),
  ('67a8d512-355e-5599-bb5a-f380ee9617d0','2de29964-53f5-5dca-a4d4-e8b7cc454867','2026-04-17 11:13:03','vs Damm','Central zurdo de buenas cualidades físicas: 1.85 m o más, de  complexión fuerte, buena velocidad y aceleración. Jugador con margen de mejora en conceptos tácticos y nivel técnico, pero con gran proactividad para jugar hacia adelante, ganar metros en conducción, progresar con pases interiores. Es fuerte en duelos, debe mejorar timing pero sale  de zona y es bueno en cobertura de profundidad. Perfil con potencial alto, próxima temporada en cantera profesional seguro.','NB','Firmar'),
  ('ce4fe3ae-74e8-59c9-8f80-b0fde6b2e0c2','6937adc8-81e7-5276-8321-e0a85bd74609','2026-04-17 11:17:16','vs Damm','Lateral zurdo de gran perfil físico: 1.85 m aprox, fuerte aunque con margen de crecimiento físico, no da sensación de estar hecho. No es explosivo pero tiene buena velocidad en carrera. Perfil que puede pasar a mediocampo por características. Por hacer en conceptos pero con cualidades físicas especiales.','NB','Firmar'),
  ('0c4778f4-718a-579c-90fc-24e706d22f6c','21bc11a8-03b5-57c4-bbb1-f89f2dbcccc3','2026-04-17 11:19:28','vs Damm','Extremo diestro por izquierda. Buen perfil físico, rápido, vertical para buscar 1v1. Tiene poco uso de zurda y me da sensación de que técnicamente le falta.','NB','Seguir'),
  ('b76f30a4-555e-5ab1-b48c-f804694574a1','230b7500-26a5-5d73-9344-2a559484e238','2026-04-17 11:20:56','vs Damm','Delantero centro de perfil físico interesante, grande y fuerte. Poco impacto en juego, no puedo valorarlo más allá del físico.','NB','Seguir'),
  ('ec64bc3a-48cb-51fd-9fe6-1519a44df0b7','0e34fbc4-a0f7-5802-a8bd-b078c81c3d31','2026-04-17 11:22:01','vs Badalona','Central diestro de buen perfil físico, aún por hacer. Da sensación de que le faltan centímetros por ganar, es delgado, con poco músculo. Rápido y ágil. Jugador con predisposición para jugar hacia adelante, conducir y dar pases en largo. En defensa es agresivo, a veces se precipita y le falta algo de contundencia, pero es central moderno.','NB','Firmar'),
  ('6a0a8570-c4a2-5ac0-b080-f6ddc4661ca5','0c1ab4dc-a0ed-58d9-bf52-4d1ca03bd8a7','2026-04-17 11:24:14','vs Badalona','Extremo zurdo por derecha. Buen nivel técnico, perfil técnico medio, rápido y vertical. Busca regate. Deja algunas acciones interesantes, ver más.','NB','Seguir'),
  ('785d3d57-dcc7-5533-b294-dee1659939a5','6a18c3c3-b149-5662-bb38-7bbe797787c9','2026-04-17 13:18:24','vs Granollers','Lateral izquierdo de perfil físico muy bueno: alto (parece +1.80 m), delgado, piernas largas, explosivo, rápido, con recorrido. Margen de crecimiento físico, no está hecho. 

Jugador de buen nivel técnico, vocación ofensiva, capacidad de conducción, va hacia adelante. Golpeo mejorable en centros y pases. 

En fase defensiva debe mejorar, le falta mayor agresividad y proactividad para ir al choque. 

Es un perfil muy interesante.','NB','Firmar'),
  ('bc14029c-c670-56fa-b192-54854f26a636','ccd6f17e-faef-5214-9a8e-1ea863909c90','2026-04-17 13:24:40','vs Granollers','Extremo de buen perfil físico, diestro por izquierda. Resiste choques. Le falta chispa y mayor impacto en juego.','NB',NULL),
  ('e43e9b26-bf71-5755-add7-1b7541cdd8bb','64c162b1-75d3-5f34-9a00-1939664d085d','2026-04-17 21:02:31','vs PSG','Delantero centro de perfil físico top, con autosuficiencia y capacidad para generar sus propias ocasiones en conducción e incluso regates en corto. Muy potente, es rápido. Con capacidad de finalización. Lo veo jugando fútbol profesional próxima temporada.','NB','Firmar'),
  ('87d6492a-8f4d-56f4-b6f9-9c91e728002e','0ced2d83-2178-5391-905e-7ac9f55837be','2026-04-17 21:07:55','vs PSG','En este partido de fuerte exigencia física me deja dudas su impacto, ya que le penaliza su perfil.','NB',NULL),
  ('b18aeb6e-58a5-5e1f-9496-ec4b47912cf1','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2026-04-18 15:04:14','vs PSG','Atacante capaz de destacar en todas las posiciones ofensivas. Muchos recursos y facilidad para generar. Lo veo a primer nivel','NB','Firmar'),
  ('69a1ecf5-c961-52e2-b09c-c49ae191ddc6','77d754f5-9d95-5aef-acae-d757fd446e8e','2026-04-18 15:06:33','vs Kelme','Jugador de buen rendimiento actual porque físicamente es poderoso y se impone, aunque creo que no va a desarrollarse más.','NB',NULL),
  ('0eac855a-bdd1-577c-8f24-92b8b421c128','828d903c-17b3-5251-bc44-07d3510beece','2026-04-18 15:15:54','vs Kelme','Mediocentro de buen nivel que temporada que viene puede estar jugando en cantera pro perfectamente. Me deja dudas sobre si puede adaptarse a 8, le falta algo más de técnica. Pero es jugador de buenas características. No top.','NB','Seguir')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('68d18a8d-e01b-55d7-b4c7-5cbde76b01b5','9b226af1-936e-58b6-8712-60344b09f28e','2026-04-18 15:22:56','vs Kelme','Opinión similar. Lo veo para cantera pro pero le falta más ritmo en mi opinión.','NB','Seguir'),
  ('c453249c-1326-55bb-a342-2c9653613435','be839e4a-2bf2-50af-af96-f2dfb9859b6f','2026-04-18 15:25:12','vs Patacona','Central diestro por izquierda. Bien perfil físico, estatura +1.85 y parece que aún con margen de crecimiento. Delgado, velocidad y agilidad correctas. Jugador con buenas intenciones con balón, jugando hacia adelante sobre todo con pases. Irregular en duelos individuales, le cuesta un poco la cobertura de profundidad. Quiero verlo en un campo más grande.','NB','Seguir'),
  ('1e19313e-766e-5ca5-8614-c20ed25e184f','a368b43b-4598-5d6b-987a-e4b3bf15c986','2026-04-18 18:29:10','vs Patacona','Por perfil físico, condiciones técnicas y polivalencia es jugador con potencial como lateral derecho. Lo veo en filial próxima temporada. Dinámico, fuerte, rápido.','NB','Seguir'),
  ('294082e4-f45d-5ca0-b4f7-b60984dcd2b5','7f9d85c9-986b-55ae-9dd8-2ea9cd4020a7','2026-04-18 20:24:13','vs Valencia Juv B','Lateral derecho de buen perfil físico: 1.80 m aprox, delgado, con gran margen de crecimiento en cuanto a musculatura. Buena velocidad y recorrido. Jugador competitivo y de carácter. En defensa hace un buen trabajo ante Jerry, capaz de frenarlo pese a la diferencia física. Llega con criterio a línea de fondo. Jugador al que quiero ver en estas últimas jornadas.','NB','Seguir'),
  ('cad04725-3d95-555d-bff7-c2cecb676e98','c309b0e8-15c9-5a95-80de-2a3377870151','2026-04-19 13:44:15','vs Getafe B','Lateral derecho de potencial físico muy bueno: alto, fuerte, rápido, con recorrido. Vertical en ataque, con recursos individuales y capacidad de llegada a último tercio. En defensa aún tiene problemas, puede ganar mayor solidez. Transferencia clara a fútbol profesional.','NB','Firmar'),
  ('f1970a6b-e3e7-59b4-8d91-951fe0006c3f','efe326d8-b336-572e-9ffc-d6f344102799','2026-04-19 13:47:38','vs Vazquez Cultural','Pocos minutos, pero se le ve un perfil físico extraordinario. +1.90 m, de gran estructura muscular. Decide bien en área en la acción que tiene.','NB','Seguir'),
  ('2624c180-5050-5b38-8dc5-6294febca155','fa85303a-3bd7-52d6-8444-e2c8991e6128','2026-04-19 18:16:57','vs Torre Levante','Por perfil físico, jugador a firmar. Es alto, delgado pero de buena complexión física, bastante potente, bien de agilidad sin ser especialmente rápido. Defensivamente tiene mucho que mejorar, débil en duelos e inconsistente en general. Con balón da sensación de que puede aportar más de lo que hace.','NB',NULL),
  ('2dffe309-44ae-5516-b454-db7003893ae0','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2026-04-19 18:18:34','vs Torre Levante','Jugador de perfil físico muy bueno, aunque ya hecho totalmente. No lo veo progresando más en este sentido. Destaca por fuerza para afrontar duelos, sólido en defensa, con recorrido. La principal diferencia con el otro Moussa (en mi opinión superior Traore) es que es este es más rígido en general. Con balón buena técnica, capacidad de conducción y llegada a último tercio.','NB','Seguir'),
  ('7a712819-f683-5910-bbf7-cdb22fe3d9c0','b3bf7333-6b04-52ef-8cfb-b06a60cacb98','2026-04-19 18:21:07','vs Torre Levante','Buena estructura para evolucionar físicamente, delgado y de poca potencia aún. Tampoco lo veo especialmente veloz, aunque es ágil. Dentro del área le falta lectura e instinto en situaciones de centros y pases laterales. Tengo que verlo más.','NB',NULL),
  ('bfeeff95-d29f-5f3a-bd0d-c25c85f6e69b','24c00223-606d-5dc5-a82c-4af68b159afb','2026-04-19 18:22:52','vs Torre Levante','6 tipo Arapio, Javi Tena…Estatura cercana al 1.90 m, complexión fuerte, agilidad decente aunque de ritmos bajos. Es jugador que no puede adaptarse a 8. Le veo transferencia a categorías superiores por físico pero dudas sobre nivel.','NB',NULL),
  ('0c5153fd-a19d-5537-b47b-551edc29e0d6','77c9daec-cd0c-5a34-8a10-af13b1fbff4b','2026-04-19 18:25:08','vs Torre Levante','Jugador de nivel técnico alto, comprensión del juego, capacidad para generar ventajas individualmente y asociarse. Activó en fase defensiva. Perfil de 8 que aún puede fortalecer físico (me da sensación de que debe estar más fino y ganar mayor músculo).','NB',NULL),
  ('b21930dd-5e5a-53e3-83f6-7b34fee84807','7d95c3b7-f358-5d29-a7a3-28b73b305d38','2026-04-20 16:14:27','CASTELLÓN B - Valencia B','Central diestro con una estatura algo superior a 1''85 m y complexión delgada. Poco consistente en defensa hoy y no ha aportado demasiado con balón. Tiene un potencial alto pero me genera dudas.','RP',NULL),
  ('ef1f6b8d-0956-5248-a9d2-1a1bf17ba6f9','3e35cc0f-3fdb-5ef3-b69b-e32e80449822','2026-04-20 16:16:31','CASTELLÓN B - Valencia B','Extremo zurdo con una estatura alrededor de 1''80 m y complexión delgada. Buena zancada, aunque no me ha parecido especialmente rápido. No ha dejado acciones destacadas. Por edad y perfil, ver más.','RP','Seguir'),
  ('54092849-d3fe-5e8f-9c0d-516014a29ad3','06f721a7-22ad-52e8-bc59-5216db7f9b1d','2026-04-20 16:19:25','Castellón B - VALENCIA B','Lateral izquierdo con una estatura baja y complexión normal. Nivel técnico muy elevado, buena arrancada y cambio de ritmo para superar rivales a varias alturas y mucha personalidad para ser agresivo con balón y tratar de avanzar en conducción.','RP','Seguir'),
  ('98496a77-7ef9-575d-af07-41f798498375','02c89ceb-1b60-5123-bcff-e9603faccf1d','2026-04-20 16:21:48','Castellón B - VALENCIA B','Central diestro con una estatura algo superior a 1''85 m y complexión más o menos fuerte. Muy bien corrigiendo. Bastante correcto durante todo el partido y ganador por arriba, aunque sin demasiadas acciones top. Perfil interesante.','RP','Seguir'),
  ('6009eef9-aa8d-5f06-a2a7-6a6e1811c413','089240a8-1dca-5d95-bb77-e26188c45d68','2026-04-20 16:24:29','Castellón B - VALENCIA B','Central zurdo con una estatura algo superior a 1''85 m y complexión más o menos fuerte. Algo pesado de movimientos, y en carrera no es rápido pero no me ha parecido especialmente lento. Bastante calidad defensiva y bien en duelos. Con balón es correcto.','RP','Seguir'),
  ('af638a2f-e36e-546d-a7b0-7c7e257a38ce','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2026-04-20 16:25:41','Castellón B - VALENCIA B','Extremo diestro con una estatura alrededor de 1''80 m y complexión muy fuerte. Rapidísimo tanto en carrera como en primeros metros, con un cambio de ritmo potentísimo. Buen nivel técnico para la jugada individual, aunque sin destacar. Debe mejorar la última acción, pero es potencial élite.','RP','Firmar'),
  ('3ede7c88-999c-53ea-b68b-fb9df9a69b4d','ba03c5a9-ab88-5212-a812-37e5c096cacc','2026-04-20 16:28:04','Castellón B - VALENCIA B','Centrocampista zurdo de tercera altura, perfil mediapunta. Estatura baja y complexión ligera. Nivel técnico elevadisimo y muy buena creatividad y visión de juego. Peligroso en últimos metros a través de último pase, disparos y llegadas a área. Veo un jugador de primera división, con algunas dudas por el perfil físico y táctico.','RP','Decidir'),
  ('480203d6-57db-55bf-b69d-b2509521e97d','70b245a8-07a4-5a82-b89f-808bbf019cbf','2026-04-20 16:29:36','Castellón B - VALENCIA B','Extremo diestro, en el partido actuando a pierna cambiada. Perfil físico medio en cuanto a estatura, complexión y velocidad. Técnicamente bien, pero sin acciones determinantes.','RP',NULL),
  ('51e8fd07-13cb-52c4-bf69-e2e07d7489f3','2fca2493-701f-5ef3-b2ed-345e292d79d0','2026-04-20 16:30:07','Castellón B - VALENCIA B','Centrocampista diestro de primera altura, perfil mediocentro pero en el partido actuando en doble pivote. Estatura alrededor de 1''80 m y complexión fuerte. Hábil para reaccionar rápido y dominar en distancias cortas, aunque no le veo especialmente rápido. Con balón es muy discreto, pero es intenso en duelos y tiene cierta calidad defensiva para ser especialista en ese rol.','RP','Decidir'),
  ('71360e54-f5c2-5067-b04c-a1ed75d1ede5','b0c59fb9-eb19-5d3b-a7b1-f4a027f1b743','2026-04-20 16:30:49','Castellón B - VALENCIA B','Extremo diestro, en el partido actuando a pierna cambiada. Estatura medio-baja, complexión normal, pero con una velocidad y un cambio de ritmo peligrosísimos. Buena técnica y hábil para desbordar en 1vs1. En el partido marca dos goles.','RP','Firmar'),
  ('18643096-6c3d-59b2-9235-a446b809c2d4','0d7a26e4-65fb-5aee-a24a-90783eac7e8f','2026-04-20 16:33:08','RODA JUV. A - Levante Juv. A','Centrocampista de segunda/tercera altura, perfil organizador, interior con llegada o mediapunta, pero que en su equipo participa en las jugadas desde el primer pase. Perfil físico medio, bastante ligero. Trato de balón sobresaliente y un criterio, visión y ritmo excelentes para esconder el balón y organizar la circulación del equipo. Acompaña bien la jugada y tiene un desplazamiento interesante para pases y disparos desde la frontal.','RP','Seguir'),
  ('9228e053-6033-5584-b8a7-e3f395e0e4a7','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2026-04-20 16:33:40','RODA JUV. A - Levante Juv. A','Centrocampista de pefil ofensivo con una estatura algo superior a 1''80 m y complexión delgada. Agresivo en duelos y vertical con balón para tratar de progresar a través de pase y conducción. Agelerador de jugadas con un nivel técnico alto y buena llegada en últimos metros. No es su mejor partido, pero tiene un perfil muy bueno.','RP','Firmar'),
  ('d4f96830-4ed7-5279-b4a2-5933cd5ad5f8','273cd1c4-0557-59ec-9667-a6fd040a25b2','2026-04-20 16:34:09','RODA JUV. A - Levante Juv. A','Lateral derecho con una estatura algo inferior a 1''85 m y complexión fuerte. Partido correcto, sin más. Buen perfil, pero esta temporada no está a buen nivel.','RP',NULL),
  ('3c85c1e7-4910-53ac-a101-3f274f1df205','cb235efe-dd4b-5a5d-9e53-a89c15d56e2b','2026-04-20 16:34:35','RODA JUV. A - Levante Juv. A','Delantero centro con una estatura algo superior a 1''80 m y complexión normal. Atacante agresivo en el duelo y en movimientos, tanto para ir al espacio como para venir a recibir. Tiene calidad y criterio para proteger el balón de espaldas y descargar. En metros finales tiene instinto y define bastante bien. No es jugador top, pero tiene unas condiciones interesantes.','RP','Seguir'),
  ('073c0665-384a-5800-907a-ee1c3f7bc219','ae1103cb-1258-5669-8b41-8e67a9cdb7b7','2026-04-20 16:35:10','RODA JUV. A - Levante Juv. A','Lateral izquierdo con una estatura algo inferior a 1''80 m y complexión fuerte. No es lento. Jugador correcto que no aporta demasiado con balón. En defensa es agresivo, pero no tiene un nivel top.','RP','Seguir'),
  ('4ff6029e-3cce-5318-a6b8-5dcd25fe7b21','280a6d57-358a-5238-92b3-46d11b6b8707','2026-04-20 16:35:35','Roda Juv. A - LEVANTE JUV. A','Atacante diestro, primero actuando como extremo derecho y después como delantero centro, con una estatura algo inferior a 1''85 m y complexión delagada pero fuerte. Buena aceleración y una zancada y potencia de carrera interesantes, pero jugador muy inestable técnica y mentalmente.','RP',NULL),
  ('d5bea0a6-4b8c-5fcb-9904-ab404219fd84','f164647d-f803-5042-95f8-3aedd0af0fb9','2026-04-20 16:36:02','Roda Juv. A - LEVANTE JUV. A','Lateral izquierdo con una estatura medio-baja, aunque con margen de crecimiento, y complexión normal. Pocas acciones, pero ha definido muy bien un par de jugadas defensivas por pura velocidad y agresividad en el duelo. Con balón correcto.','RP','Firmar'),
  ('81c916b6-867d-5d87-902f-86e4ac9df3be','26bad713-122f-5f1e-899f-a048c4e9fcd5','2026-04-20 16:36:30','CASTELLÓN CAD. A - Valencia Cad. A','Centrocampista diestro capaz de intervenir en las tres alturas desde una posición de doble pivote o interior con recorrido. Estatura alrededor de 1''85 m, complexión delgada. Agresivo en el duelo y en la toma de decisión con balón. Vertical en la intención a través del pase y la conducción. Técnicamente mejorable.','RP','Seguir'),
  ('0ec4db60-ce83-52cd-a3e5-604f1bcba3bc','45080b56-6d23-5e5b-8607-6cc38cf96896','2026-04-20 16:37:04','Castellón Cad. A - VALENCIA CAD. A','Lateral izquierdo con una estatura alrededor de 1''85 m y complexión fuerte. Algo pesado visualmente, pero muy agresivo en el duelo, ganador. Con balón hace un partido correcto. No le he apreciado un gran recorrido.','RP','Seguir'),
  ('d568978b-6d11-566c-8c2f-6fed3356160f','08b700a3-c3fd-5b86-ad04-35a0af473728','2026-04-20 16:38:50','Castellón Cad. A - VALENCIA CAD. A','Centrocampista diestro de primera/segunda altura, para actuar como mediocentro, en doble pivote o interior cerca de la base. Estatura alrededor de 1''85 m y complexión normal. Nivel técnico muy alto y buen criterio para la distribución. Correcto en duelos.','RP','Seguir'),
  ('7bb68b07-e153-5de4-b61f-e9a61a7c68b4','d1ba3e4d-372e-5543-9871-9d41c0a94349','2026-04-20 16:40:07','Castellón Cad. A - VALENCIA CAD. A','Extremo diestro jugando en banda izquierda, de estatura baja y complexión ligera. Rápido y con buen cambio de ritmo. Habilidoso para el 1vs1 y con bastante peligro en el último tercio a través de últimos pases y llegadas al área.','RP','Seguir'),
  ('1a888e4f-0b35-5ba0-b522-369224a22597','bc8cb2ea-81b1-5b79-b03d-53e4ba6ef98f','2026-04-20 16:41:25','Castellón Cad. A - VALENCIA CAD. A','Extremo zurdo jugando en banda derecha, con una estatura algo inferior a 1''85 m y complexión más o menos fuerte. En el partido marca un gol, pero no deja demasiadas acciones destacables.','RP','Seguir'),
  ('dd0dd829-6c5b-5113-ac6a-269a8e5b5c69','1078d34d-bc99-5ba8-901d-311f5cd37b3d','2026-04-20 16:45:42','Castellón Cad. A - VALENCIA CAD. A','Delantero centro con una estatura alrededor de 1''85 m y complexión fuerte. Muy inteligente para moverse y chocar con los defensas, con mucha facilidad para obtener ventajas en el duelo. En el partido marca un buen gol y muestra un gran olfato. Lleva 22 goles con solo 12 titularidades.','RP','Firmar'),
  ('daf96551-fe2f-51d6-8d64-e031e7040595','fd24a655-1327-57e0-914c-32247ffd8dea','2026-04-20 16:47:38','Castellón Cad. A - VALENCIA CAD. A','Lateral derecho con una estatura algo inferior a 1''85 m y complexión fuerte. No parece rápido y visualmente es algo pesado. Bien en duelos y técnicamente válido para ayudar al equipo.','RP','Seguir'),
  ('905d3008-b581-5b75-8c3a-8c9c2f5b0e7b','817899a9-d9d5-58e4-815f-df059f50c7eb','2026-04-20 16:49:15','Castellón Cad. A - VALENCIA CAD. A','Centrocampista de primera o segunda altura, para actuar en doble pivote o como interior de base. Estatura algo superior a 1''80 m y complexión más o menos fuerte. Bien en el duelo y con mucha calidad y criterio para distribuir. Buen ritmo de juego también.','RP','Seguir'),
  ('75ea7b1c-58a4-5ea1-8d14-e4b42973ee4b','26280ca8-5106-5777-a599-eb04557be939','2026-04-21 15:32:14','Roda Juv. A - LEVANTE JUV. A','Centrocampista diestro de segunda/tercera altura, perfil interior con llegada. Estatura algo inferior a 1''75 m, complexión normal. Técnicamente notable y con una visión y creatividad muy destacadas. Agresivo en toma de decisión, suele buscar verticalizar con pase o conducción, pudiendo incluso desbordar a su marca.','RP','Seguir'),
  ('8a5ce339-d086-5478-bd19-682e5fd324d0','6a18c3c3-b149-5662-bb38-7bbe797787c9','2026-04-21 15:33:40','vs Reus / Nástic','Lateral izquierdo que se está asentando en la posición, perfil ofensivo habituado a jugar como extremo. Buen perfil físico, aún por hacer: es delgado, rápido, con musculatura por hacer, tiene buena aceleración. En ataque es vertical, tiene recursos individuales. En fase defensiva aún es endeble, le falta más solidez en duelos y conceptos. 

Es jugador aún por hacer pero al que veo explotando por características.','NB','Firmar'),
  ('affd0435-10e2-5525-b89b-ebc45fcc22d8','303133d8-b787-535b-aa2c-b22fe5902e3b','2026-04-22 11:06:07','vs Tenerife','Juega de extremo, en mi opinión más condiciones como delantero centro. Aun así deja alguna acción de mucho nivel. Jugador de cualidades físicas top, con técnica irregular (capaz de superar en 1v1, mejor regate del que parece, más agilidad también; aunque con precisión mejorable para asociarse). Aún inconsistente en el juego y en toma de decisiones, da impresión de que no está adaptado a Arenas. Me parece un perfil con unas condiciones top','NB','Firmar'),
  ('fde36684-cd4c-5d33-aa12-b884f9d8e969','ccf89672-77f6-5934-855a-8aa2baf1b8d2','2026-04-22 11:59:47','vs Sevilla C','Juega de central zurdo. Perfil físico interesante, alto, delgado, de piernas largas. Tiene recursos en salida de balón, tanto en conducción como filtrando. En defensa aún es endeble, debe ser más sólido en duelos y en acciones en general.','NB','Seguir'),
  ('be165b13-e919-597e-b777-876299378203','1b35dbe4-1e7a-5e19-a536-89f694f20083','2026-04-22 13:31:09','vs Atlético','Lateral derecho de físico medio, de buen nivel técnico (buena capacidad para centrar). Defensivamente normal. Jugador OK pero al que no le veo mayor recorrido.','NB',NULL),
  ('17ce1586-0147-5bde-997b-87b169819de7','add54e13-eab8-54bc-95f3-642f24ad1274','2026-04-22 13:42:22','vs Atletico','Mediapunta / Extremo zurdo de muchísima calidad, nivel técnico excelente. Jugador de 1v1, capaz de generar individualmente, mucho desequilibrio y finalización.','NB','Firmar'),
  ('3e920271-6e33-5003-bde7-6ba9116ef965','6d230e2b-b0c7-57a2-8d2d-5ef2ab5a3aa3','2026-04-22 13:45:58','vs Atletico','Delantero centro de condiciones físicas excelentes, dominador. Buen nivel técnico y capacidad para jugar de espaldas, ganador por arriba. Muy completo.','NB','Firmar'),
  ('002e4f36-991b-520c-96d9-992751d0747a','91786d27-c3b6-52e3-9dd1-513d548f3045','2026-04-22 13:48:20','vs Real Madrid','Lateral izquierdo de buen perfil físico, que se muestra con capacidad para ganar metros en conducción. Sólido defensivamente.','NB','Seguir'),
  ('6a6239c6-671b-55b1-9e46-e5292b8ee593','3dae5ada-78db-5052-9fea-96d82ca9f506','2026-04-22 16:10:00',NULL,'Delantero centro de perfil físico medio, que no destaca especialmente en este sentido. Juega bien de espaldas, se mueve bien en área, tiene finalización. No tiene tanto impacto en partidos vistos. Necesito verlo más.','NB','Seguir'),
  ('bceb0576-b63f-553b-8123-111e570158be','81b45e1e-8d3d-593f-9277-db7874f6ab11','2026-04-24 16:25:19','vs Badajoz Juv. A','Central diestro con una estatura algo inferior a 1''90 m y complexión delgada. En el partido no me ha parecido lento y con balón ha estado muy bien, pero el contexto era muy poco exigente.','RP','Decidir'),
  ('8e384c01-edf0-5af3-aade-6f6b35630608','2da778d0-150f-5c60-85d7-4c3a10c707f7','2026-04-24 16:26:39','vs Badajoz Juv. A','Central diestro con una estatura alrededor de 1''90 m y complexión delgada. En el partido ha dejado dos acciones de velocidad punta muy buenas. Con balón correcto. Evaluar mejor en contextos de mayor dificultad.','RP','Decidir'),
  ('043b49c6-cba8-565c-aab3-8e22d68e7fe7','797878b8-bbd7-5a02-826d-1be038fa9978','2026-04-24 16:28:35','vs Badajoz Juv. A','Extremo zurdo jugando a pierna cambiada. Estatura alrededor de 1''80 m, complexión delgada. Muy habilidoso en 1vs1 y rápido de movimientos, no sé si tanto en carrera. Mucha facilidad para desbordar y meter centro con ambas piernas. Poca llegada propia a portería.','RP','Seguir'),
  ('21ba95fa-bd69-51ea-b2e7-82d18a085802','dd93f051-fd27-569d-919d-b9d507bcf751','2026-04-24 16:30:38','vs Badajoz Juv. A','Delantero centro diestro con una estatura alrededor de 1''85 m y complexión fuerte, algo pesado. Excelente en movimientos y en duelos directos con su marca. Buen juego de espaldas y muy hábil usando su cuerpo para proteger el balón y ganar la posición. Gran olfato goleador en últimos metros. Jugador que hace las cosas muy bien y que va a marcar goles independientemente de la categoría por puro instinto. El físico genera alguna duda.','RP','Firmar'),
  ('3a4526a1-99cd-557e-ae7e-97cc6d2aed4e','0ced2d83-2178-5391-905e-7ac9f55837be','2026-04-24 16:34:14','vs Badajoz Juv. A','Centrocampista diestro de segunda/tercera altura, para actuar como interior con llegada o mediapunta. Estatura alrededor de 1''85 m, complexión más o menos fuerte. Nivel técnico elevadísimo para controles, pases y conducciones. Gran criterio y buena toma de decisión en el último tercio. Muy buen jugador que anda sobrado en juveniles, pero hay que ver cómo le sienta el paso al fútbol semiprofesional.','RP','Decidir'),
  ('52b31496-7e7e-5de5-b572-e7162c0b83a1','3b76ec9b-0609-5acc-bdd5-416fb7feb213','2026-04-24 16:37:11','vs Badajoz Juv. A','Extremo zurdo jugando a pierna natural. Estatura alrededor de 1''80 m y complexión delgada, con piernas largas. Buen nivel técnico, habilidoso en el 1vs1 y eléctrico de movimientos. No usa pierna derecha, bastante incómodo en banda izquierda. Buen jugador, pero a pierna natural no es élite.','RP','Seguir'),
  ('7d3a0389-5153-5271-bef7-e12c8a0ffbce','07d4be16-ea4c-5d5d-b2ca-c06fbcc0523f','2026-04-24 16:38:56','vs Badajoz Juv. A','Lateral derecho con una estatura algo inferior a 1''80 m y complexión normal. Partido correcto, poco exigido en defensa y con buenas decisiones en ataque, doblando a su extremo y participando en la circulación, pero sin aportar grandes ventajas.','RP','Seguir'),
  ('f193a2e7-57f7-56bf-8931-7a319645bb04','de72106d-f624-52ef-b0e4-dcab76c61597','2026-04-24 16:40:53','vs Badajoz Juv. A','Lateral izquierdo con una estatura algo superior a 1''80 m y complexión delgada. Explosivo y muy rápido en carrera. Tiene mucho recorrido y capacidad para doblar muchas veces. Con balón es muy bueno técnicamente y agresivo en la toma de decisión para progresar, acelerar, centrar o incluso desbordar en jugada individual. Partido poco exigente, pero muy buena impresión.','RP','Decidir'),
  ('0d911997-3f36-5d12-9239-c3cd4d00664a','fc6cee27-b26e-5ee7-8272-8146ffb74520','2026-04-24 16:43:07','vs Badajoz Juv. A','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Estatura algo inferior a 1''80 m, complexión fuerte. Duro en duelos, con bastante agresividad sin balón y calidad defensiva para robar. Muy seguro en el pase, aunque el partido no era demasiado exigente.','RP','Firmar'),
  ('02ee639b-8d26-5a65-8a19-9688e4b2f8ef','b54c0261-1f7e-5c1a-b74a-c1a29f26774e','2026-04-24 16:44:23','vs Badajoz Juv. A','Centrocampista zurdo de segunda/tercera altura, estilo interior con llegada o mediapunta. Estatura alrededor de 1''75 m, complexión ligera. Acelerador de jugadas. Tiene mucha calidad para participar en el juego asociativo y verticalizar a través del pase o la conducción para atacar la última línea. En el partido marca un gol y también tiene un par de buenas llegadas al área. Buen jugador, pero el perfil físico no me convence demasiado.','RP','Seguir'),
  ('13d2b13f-20ab-5293-b73e-c87acf59fb82','5d42d513-07a9-5ac0-9232-e5b73a4c9b93','2026-04-24 16:47:51','vs Badajoz Juv. A','Centrocampista diestro de segunda altura, estilo interior con recorrido o para actuar en doble pivote. Estatura algo superior a 1''85 m, complexión fuerte, muy imponente físicamente. Nivel técnico elevado para retener la posesión y buscar la mejor opción para hacer progresar la jugada. También tiene recorrido y una llegada al área interesante.','RP','Firmar'),
  ('57f723d7-96f5-56da-8124-688cb6c46f12','52994667-4d67-5956-ad62-e773226c6ff7','2026-04-24 16:54:56','vs Real Madrid Juv. A','Central diestro con una estatura algo inferior a 1''90 m y complexión fuerte. No parece rápido y en el partido no demuestra mucho, pero me ha llamado la atención el físico y el hecho de llevar unos cuantos partidos en DH siendo 2009.','RP','Seguir'),
  ('4928b09b-cef8-592a-b181-9f094f8018a7','2fca2493-701f-5ef3-b2ed-345e292d79d0','2026-04-26 13:54:49','vs Espanyol B','Invertir fuerte, proponerle al padre inversión por porcentaje y mantenerlo dentro. Es un jugador con condiciones físicas increíbles, le da de sobra para jugar de 8 con su técnica. Muy agresivo en defensa, ganador de duelos.','NB','Firmar'),
  ('e88049ee-37e2-5fe4-92cd-be53e6989a1b','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2026-04-26 13:58:28','vs Espanyol','Jugador con perfil físico de Primera División. Próxima temporada debe estar cedido en Segunda.','NB','Firmar'),
  ('2ee8f3cd-bc7e-5b2e-a408-59c0cb92d652','089240a8-1dca-5d95-bb77-e26188c45d68','2026-04-26 14:03:48','vs Espanyol','Central zurdo de buen perfil físico, sin ser excelente. Le falta más velocidad en cobertura de profundidad. Correcto en fase defensiva y en ataque, sin parecerme un central del nivel/potencial de Iker Córdoba por ejemplo','NB',NULL),
  ('bed580b2-15ae-5d25-bf26-1397277961dc','02c89ceb-1b60-5123-bcff-e9603faccf1d','2026-04-26 14:06:00','vs Espanyol B','Central diestro de buen perfil físico, más Junior que Huseini. Es rápido y ágil, juega a ritmos altos. Buena salida de balón,  capacidad de conducción. Dolido en duelos. Me gusta más que Fontanet. Tampoco me parece algo demasiado especial.','NB','Seguir'),
  ('8dd70db1-b5c8-5b87-a66f-e802044480a9','6f9306fe-acd9-56df-afa0-de3ff46501fc','2026-04-26 14:12:51','vs Valencia B','El perfil físico es muy bueno en estatura y fuerza, dudas sobre velocidad y agilidad. Central con tendencia al fallo que no lee bien y tiene errores de conceptos, en duelos bien. Con balón juega hacia adelante sin destacar.','NB','Seguir'),
  ('5a0f0137-971b-562d-99f7-96caadf39f84','15ed7516-aade-53dc-8d18-4c4c737b05c3','2026-04-26 14:15:15','vs Valencia B','Jugador de condiciones muy buenas, al que le está costando el paso a filial. Buenas acciones aisladas pero sin tanto impacto en juego del equipo, le falta definir posición y eso va a ser un handicap para él. De todas formas me deja sensaciones positivas.','NB','Seguir'),
  ('0394443c-9518-5e4d-ac21-22e7a21eb822','bae4ce7e-ff60-5fef-9282-c87535af0d84','2026-04-26 14:17:26','vs Valencia B','Lateral derecho de perfil físico muy bueno, pero que me deja dudas en directo por su capacidad defensiva. Bien ataque, más por empuje que por técnica. La sensación no es positiva.','NB',NULL),
  ('6a476ac2-0a23-56e9-806f-981537ffd79d','4679ba77-4527-5a5b-bbbf-c3540a6030f7','2026-04-26 20:07:30','vs Nucia','8 de 1.90 con buen nivel técnico, capacidad para generar en conducción, asociarse y pisar área. Agresivo en fase defensiva, mejor hacia adelante que hacia atrás. Es centrocampista de perfil transferible a fútbol profesional.','NB','Firmar'),
  ('60a28bab-6f59-5a72-b858-25736597b553','a368b43b-4598-5d6b-987a-e4b3bf15c986','2026-04-27 16:03:16','vs Villarreal Juv. A','Carrilero derecho, para mí con perfil de lateral, con una estatura algo superior a 1''75 m y complexión fuerte. No destaca por su velocidad, pero tampoco es lento. Es difícil de superar en carrera porque usa bien su cuerpo y en ataque es capaz de crear peligro cuando llega desde atrás con y sin balón. Defensivamente bien en el 1vs1, aunque sufre más cuando juega de central y tiene que enfrentarse a atacantes más grandes. Como lateral le firmaría seguro, pero mientras siga en Castellón va a ser central en línea de tres.','RP','Decidir'),
  ('5a278c96-9493-50be-8fdd-7836d767e59b','c8dfcf33-deda-583b-85f2-a4217144dda3','2026-04-27 16:06:46','vs Castellón Juv. A','Lateral izquierdo con una estatura alrededor de 1''85 m y complexión atlética. Físicamente está muy bien y tiene recorrido, pero para mí le falta defensivamente y con balón para ser top. Pendientes de evolución.','RP','Seguir'),
  ('a5607ef8-eb8c-537c-b6bf-f5f72a8b6eed','70bc0460-fbc3-5e9f-ba03-c97d97e8fed9','2026-04-27 16:07:57','vs Castellón Juv. A','Centrocampista de corte ofensivo, en el partido actuando como segundo punta, con un perfil físico bastante pobre en cuanto a estatura, complexión y velocidad. Nivel técnico muy alto, pero incapaz de tener impacto en el partido. Es un jugador de una enorme calidad, pero le he visto mal en el salto de LN  a DH','RP',NULL),
  ('32d291f7-c4b9-5332-8777-12675951f508','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2026-04-27 16:09:24','vs Castellón Juv. A','Centrocampista box to box, en el partido actuando en banda derecha. Estatura algo inferior a 1''90 m y complexión fuerte. Gran recorrido, muy bien en duelos y con capacidad de ganar metros en conducción. Sin ser un partido brillante, buena actuación y con peso para ser debut en DH. Jugador de un potencial altísimo','RP','Firmar'),
  ('54f7d696-6510-598a-ace4-0ac3d8328fd0','4bb6f236-8e41-510f-865f-adaf0464749e','2026-04-27 16:10:47','vs Castellón Juv. A','Lateral derecho con una estatura algo inferior a 1''85 m y complexión delgada. Con balón tiene técnica y es ágil para escapar de marca y generar ventajas a través del pase y la conducción. También juega bien por dentro y tiene recorrido. En defensa es bastante blando, tiene margen de mejora. Jugador con un perfil muy interesante','RP','Seguir'),
  ('848676c2-082f-5369-9330-f56c7a491ad8','a048706c-57ed-56e7-9c1c-eaf7ed81af94','2026-04-27 16:13:32','vs Atzeneta','Lateral izquierdo, en el partido actuando como central zurdo en línea de tres, con una estatura algo superior a 1''75 m y complexión fuerte. Defensivamente es excelente, muy difícil de superar en el duelo, incluso por arriba, y con una lectura, timing y técnica defensiva muy alta. Con balón es correcto.','RP','Firmar')
ON CONFLICT (id) DO NOTHING;

